```javascript
const fs = require("fs");

// Síncrono (bloqueante)
const data = fs.readFileSync("archivo.txt", "utf-8");
fs.writeFileSync("salida.txt", data.toUpperCase());

// Asíncrono con callbacks
fs.readFile("archivo.txt", "utf-8", (err, data) => {
  if (err) throw err;
  fs.writeFile("salida.txt", data.toUpperCase(), (err) => {
    if (err) throw err;
  });
});

// Asíncrono con promesas (fs.promises)
const fsPromises = require("fs").promises;
async function leer() {
  const data = await fsPromises.readFile("archivo.txt", "utf-8");
  await fsPromises.writeFile("salida.txt", data.toUpperCase());
}
```

