localStorage.setItem("datos", JSON.stringify({a: 1, b: 2}));

// Leer
const nombre = localStorage.getItem("nombre");
const datos = JSON.parse(localStorage.getItem("datos"));

// Eliminar
localStorage.removeItem("nombre");
localStorage.clear();  // todo

// SessionStorage (se borra al cerrar pestaña)
sessionStorage.setItem("temp", "valor temporal");
```

**Límite:** ~5-10 MB por dominio. Solo guarda strings.

```javascript
const emailRegex = /^\S+@\S+\.\S+$/;

emailRegex.test("user@example.com");  // true
emailRegex.test("usuario@");          // false
emailRegex.test("@dominio.com");      // false

// Explicación:
